class Admin_Model_ProductAttachment extends Admin_Model_Base_ProductAttachment
{

    public function save(Doctrine_Connection $conn = null, $skipEshop = false) {
        if ( $isNew = $this->ID == null ) {
            $this->DateTimeCreated = date('Y-m-d H:i:s');
        }
        $this->DateTimeUpdated = date('Y-m-d H:i:s');
        $this->DateTimeLastSynchronized = date('Y-m-d H:i:s');
        parent::save($conn);
    }

    public static function getAttachmentByAttachmentID(int $attachmentID) {
        return Doctrine_Query::create()
            ->from('Admin_Model_ProductAttachment pa')
            ->where('pa.ID = ?', $attachmentID)
            ->fetchOne();
    }

    public static function getAttachmentsByProductID(int $productID): Doctrine_Collection {
        return Doctrine_Query::create()
            ->from('Admin_Model_ProductAttachment pa')
            ->where('pa.Product_ID = ?', $productID)
            ->execute();
    }

    public static function getAttachmentsByProductCode(string $productCode): null | Doctrine_Collection {
        $product = Product::getProductByCode($productCode);
        if(!$product) {
            return null;
        }
        return Doctrine_Query::create()
            ->from('Admin_Model_ProductAttachment pa')
            ->where('pa.Product_ID = ?', $product->ID)
            ->execute();
    }

    public static function getAttachmentByHashAndProductID(string $hash, int $productID): self|bool {
        return Doctrine_Query::create()
            ->from('Admin_Model_ProductAttachment pa')
            ->where('pa.Hash = ?', $hash)
            ->andWhere('pa.Product_ID = ?', $productID)
            ->fetchOne();
    }




}